const items = $input.all();

const toText = (value) => String(value ?? '').trim();
const toLowerEmail = (value) => toText(value).toLowerCase();
const toBool = (value) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value === 1;
  const normalized = String(value ?? '').trim().toLowerCase();
  return ['true', '1', 'yes', 'ja', 'on'].includes(normalized);
};
const toNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const sanitized = String(value).replace(',', '.').replace(/[^\d.-]/g, '');
  const parsed = Number(sanitized);
  return Number.isFinite(parsed) ? parsed : null;
};

return items.map((item) => {
  const payload = item.json ?? {};
  const report = payload.report ?? {};
  const email = toLowerEmail(payload.email);
  const businessName = toText(payload.restaurant || payload.business_name || payload.businessName || payload.restaurant_name);
  const consentGranted = toBool(payload.consent);
  const pageUrl = toText(payload.page);
  const source = toText(payload.source) || 'impact-report';
  const clientCreatedAt = toText(payload.createdAt) || new Date().toISOString();

  const normalizedReport = {
    missed_reservations_per_week: toNumber(report.missedReservationsPerWeek),
    average_guests_per_reservation: toNumber(report.averageGuestsPerReservation),
    average_spend_per_guest: toNumber(report.averageSpendPerGuest),
    monthly_loss: toNumber(report.monthlyLoss),
    annual_loss: toNumber(report.annualLoss),
    saved_reservations: toNumber(report.savedReservations),
    payback_weeks: toNumber(report.paybackWeeks)
  };

  const errors = [];
  if (!email || !/^[\w.%+-]+@[\w.-]+\.[A-Za-z]{2,}$/i.test(email)) {
    errors.push('Bitte eine gueltige E-Mail-Adresse uebergeben.');
  }
  if (!businessName || businessName.length < 2) {
    errors.push('Restaurantname fehlt oder ist zu kurz.');
  }
  if (!consentGranted) {
    errors.push('Explizite Einwilligung ist erforderlich.');
  }
  if (!normalizedReport.monthly_loss || normalizedReport.monthly_loss < 1) {
    errors.push('Monatlicher Verlust konnte nicht plausibel berechnet werden.');
  }
  if (!normalizedReport.annual_loss || normalizedReport.annual_loss < normalizedReport.monthly_loss) {
    errors.push('Jahresverlust ist unplausibel.');
  }

  const submittedAt = new Date().toISOString();
  const valid = errors.length === 0;

  return {
    json: {
      valid,
      validation_errors: errors,
      email,
      business_name: businessName,
      consent_granted: consentGranted,
      consent_text_version: 'rais-roi-report-v1',
      source,
      page_url: pageUrl,
      lead_type: 'roi_report',
      submitted_at: submittedAt,
      client_created_at: clientCreatedAt,
      report: normalizedReport,
      missed_reservations_per_week: normalizedReport.missed_reservations_per_week,
      average_guests_per_reservation: normalizedReport.average_guests_per_reservation,
      average_spend_per_guest: normalizedReport.average_spend_per_guest,
      monthly_loss: normalizedReport.monthly_loss,
      annual_loss: normalizedReport.annual_loss,
      saved_reservations: normalizedReport.saved_reservations,
      payback_weeks: normalizedReport.payback_weeks,
      original_payload: payload,
      notification_summary: `${businessName} | ${email} | ${normalizedReport.monthly_loss ?? 0} EUR Verlust/Monat`
    }
  };
});

return $input.all().map((item) => ({
  json: {
    success: true,
    stored: true,
    message: 'Lead gespeichert.',
    responseCode: 200
  }
}));

return $input.all().map((item) => ({
  json: {
    success: false,
    stored: false,
    message: 'Lead nicht gespeichert.',
    errors: item.json.validation_errors ?? [],
    responseCode: 422
  }
}));
